```typescript
// roles.decorator.ts
import { SetMetadata } from '@nestjs/common';
export const ROLES_KEY = 'roles';
export const Roles = (...roles: string[]) => SetMetadata(ROLES_KEY, roles);

// roles.guard.ts
import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { ROLES_KEY } from './roles.decorator';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    // 1. Récupérer les rôles requis sur le handler ou la classe
    const requiredRoles = this.reflector.getAllAndOverride&lt;string[]&gt;(
      ROLES_KEY,
      [context.getHandler(), context.getClass()],
    );

    // 2. Si aucun rôle requis, accès autorisé
    if (!requiredRoles) return true;

    // 3. Récupérer l'utilisateur depuis la requête (ajouté par JwtAuthGuard)
    const request = context.switchToHttp().getRequest();
    const user = request.user;

    // 4. Vérifier que l'utilisateur existe et a des rôles
    if (!user || !user.roles) return false;

    // 5. Vérifier si l'utilisateur possède au moins un des rôles requis
    return requiredRoles.some(role => user.roles.includes(role));
  }
}

// Utilisation combinée avec JwtAuthGuard
@UseGuards(JwtAuthGuard, RolesGuard)
@Roles('admin')
@Delete(':id')
remove(@Param('id') id: string) { ... }
```
Explication : Le Reflector extrait les métadonnées du décorateur @Roles. L'utilisateur est attaché à req.user par le JwtAuthGuard. On compare ses rôles avec ceux requis.

